module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output [15:0] product
);

reg [15:0] product_reg;
reg [3:0] shift_count;

always @(*) begin
    product_reg = 16'b0;
    shift_count = 4'b0;

    for (shift_count = 0; shift_count < 8; shift_count = shift_count + 1) begin
        if (B[shift_count]) begin
            product_reg = product_reg + (A << shift_count);
        end
    end
end

assign product = product_reg;

endmodule
